# src/amazon_finder/main.py
import typer
from .search import find_products

app = typer.Typer(help="Search Amazon from the terminal.")

@app.command()
def search(query: str = typer.Argument(..., help="What you want to find on Amazon")):
    """CLI entry point – forwards the query to the scraper and prints results."""
    typer.echo(f"🔎 Searching Amazon for: {query}\n")
    products = find_products(query)
    if not products:
        typer.echo("❌ No products found. Try a different query.")
        raise typer.Exit(code=1)
    for idx, prod in enumerate(products, start=1):
        typer.echo(f"{idx}. {prod.title}\n   {prod.url}\n")

if __name__ == "__main__":
    app()
